  7	export function flyIssuerAdapter(configuredOrgSlugs: string): OidcIssuerAdapter {
  8	  const trustedIssuers = parseTrustedIssuers(configuredOrgSlugs);
  9	
 10	  return {
 11	    resolveIssuer: (issuer) => {
 12	      if (!issuer.startsWith(flyIssuerPrefix)) {
 13	        return { status: "unhandled" };
 14	      }
 15	
 16	      if (trustedIssuers === null) {
 17	        return { status: "unavailable" };
 18	      }
 19	
 20	      const trustedIssuer = trustedIssuers.get(issuer);
 21	
 22	      return trustedIssuer === undefined
 23	        ? { status: "unhandled" }
 24	        : { status: "configured", trustedIssuer };
 25	    },
 26	    validateSubjectTokenBinding: validateFlySubjectTokenBinding,
 27	  };
 28	}
