 34	function parseTrustedIssuers(value: string): ReadonlyMap<string, TrustedOidcIssuer> | null {
 35	  const slugs = value
 36	    .split(",")
 37	    .map((slug) => slug.trim())
 38	    .filter((slug) => slug.length > 0);
 39	
 40	  if (slugs.length === 0) {
 41	    return new Map();
 42	  }
 43	
 44	  if (slugs.some((slug) => flyIssuerForOrgSlug(slug) === null)) {
 45	    return null;
 46	  }
 47	
 48	  return new Map(
 49	    slugs.map((slug) => {
 50	      const issuer = flyIssuerForOrgSlug(slug);
 51	
 52	      if (issuer === null) {
 53	        throw new Error("validated Fly organization slug did not produce an issuer");
 54	      }
 55	
 56	      return [
 57	        issuer,
 58	        {
 59	          allowedSigningAlgorithms: ["RS256"],
 60	          issuer,
 61	          jwksUri: new URL(`${issuer}/.well-known/jwks`),
 62	        } satisfies TrustedOidcIssuer,
 63	      ];
 64	    }),
 65	  );
 66	}
