 68	function flyOrgSlugForIssuer(issuer: string): string | null {
 69	  const orgSlug = issuer.startsWith(flyIssuerPrefix) ? issuer.slice(flyIssuerPrefix.length) : "";
 70	
 71	  return flyOrgSlugPattern.test(orgSlug) ? orgSlug : null;
 72	}
