 78	function validateFlySubjectTokenBinding(input: {
 79	  claims: VerifiedOidcToken["claims"];
 80	  expectedAudience: string;
 81	  issuer: string;
 82	}): boolean {
 83	  const { claims, expectedAudience, issuer } = input;
 84	  const appId = claims["app_id"];
 85	  const appName = claims["app_name"];
 86	  const machineId = claims["machine_id"];
 87	  const machineName = claims["machine_name"];
 88	  const machineVersion = claims["machine_version"];
 89	  const orgId = claims["org_id"];
 90	  const orgName = claims["org_name"];
 91	
 92	  return (
 93	    isNonEmptyString(claims.sub) &&
 94	    typeof claims.exp === "number" &&
 95	    typeof claims.nbf === "number" &&
 96	    isNonEmptyString(appId) &&
 97	    isNonEmptyString(appName) &&
 98	    isNonEmptyString(machineId) &&
 99	    isNonEmptyString(machineName) &&
100	    isNonEmptyString(machineVersion) &&
101	    isNonEmptyString(orgId) &&
102	    isNonEmptyString(orgName) &&
103	    orgName === flyOrgSlugForIssuer(issuer) &&
104	    claims.sub === `${orgName}:${appName}:${machineName}` &&
105	    (claims["azp"] === undefined || claims["azp"] === expectedAudience)
106	  );
