 74	function evaluate(
 75	  rule: TokenPolicyRule,
 76	  tokenClaims: Record<string, unknown>,
 77	  request: { resource?: string; scope?: string } = {},
 78	) {
 79	  const subjectToken: VerifiedSubjectToken = {
 80	    claims: tokenClaims,
 81	    issuer: googleServiceAccountTrustedIssuer.issuer,
 82	    resolvedKeyId: "google-key",
 83	    subjectTokenType: "id_token",
 84	  };
 85	  const tokenRequest = normalizeInstallationAccessTokenRequest(subjectToken, {
 86	    resource: request.resource ?? resource,
 87	    scope: request.scope ?? "contents:write",
 88	  });
 89	
 90	  if (!tokenRequest.ok) {
 91	    throw new Error("fixture token request did not normalize");
 92	  }
 93	
 94	  return evaluateConfiguredTokenPolicy(
 95	    { subjectToken, tokenRequest: tokenRequest.tokenRequest },
 96	    validateTokenPolicyRules([rule]),
 97	  );
 98	}
